207	/**
208	 * Make a non-streaming API call and return the parsed response.
209	 *
210	 * @throws When the HTTP response is not ok, with the status and body.
211	 */
212	async function callApi(
213	  apiEndpoint: string,
214	  token: string,
215	  model: string,
216	  messages: ChatMessage[],
217	  apiTools: ToolDef[],
218	): Promise<ChatCompletionResponse> {
219	  const response = await fetch(`${apiEndpoint}/chat/completions`, {
220	    method: 'POST',
221	    headers: {
222	      'Content-Type': 'application/json',
223	      'Authorization': `Bearer ${token}`,
224	    },
225	    body: JSON.stringify({
226	      model,
227	      messages,
228	      ...(apiTools.length > 0 ? { tools: apiTools } : {}),
229	      stream: false,
230	    }),
231	  });
232	
233	  if (!response.ok) {
234	    const body = await response.text();
235	    throw new Error(`GitHub Models API error: ${response.status} ${body}`);
236	  }
237	
238	  return response.json() as Promise<ChatCompletionResponse>;
239	}
